manifest_content:
{
  "name": "caveman-installer",
  "version": "0.1.0",
  "description": "Caveman installer — detects your AI coding agents and installs caveman for each one.",
  "license": "MIT",
  "author": "Julius Brussee",
  "homepage": "https://github.com/JuliusBrussee/caveman",
  "repository": {
    "type": "git",
    "url": "git+https://github.com/JuliusBrussee/caveman.git"
  },
  "bugs": {
    "url": "https://github.com/JuliusBrussee/caveman/issues"
  },
  "bin": {
    "caveman": "./bin/install.js"
  },
  "engines": {
    "node": ">=18"
  },
  "scripts": {
    "test": "node --test tests/installer/*.test.mjs"
  },
  "files": [
    "bin/",
    "src/",
    "agents/",
    "skills/",
    "plugins/",
    "commands/",
    "dist/caveman.skill",
    "README.md",
    "LICENSE"
  ]
}

{
  "name": "@openai/codex-plugin-cc",
  "version": "1.0.5",
  "private": true,
  "type": "module",
  "description": "Use Codex from Claude Code to review code or delegate tasks.",
  "license": "Apache-2.0",
  "engines": {
    "node": ">=18.18.0"
  },
  "scripts": {
    "bump-version": "node scripts/bump-version.mjs",
    "check-version": "node scripts/bump-version.mjs --check",
    "prebuild": "mkdir -p plugins/codex/.generated/app-server-types && codex app-server generate-ts --out plugins/codex/.generated/app-server-types",
    "build": "tsc -p tsconfig.app-server.json",
    "test": "node --test tests/*.test.mjs"
  },
  "devDependencies": {
    "@types/node": "^25.5.0",
    "typescript": "^6.0.2"
  }
}

[workspace]
members = ["crates/*"]
exclude = [
  "scripts",
  # Needs nightly
  "crates/uv-trampoline",
]
resolver = "2"

[workspace.package]
edition = "2024"
rust-version = "1.94.0"
homepage = "https://pypi.org/project/uv/"
repository = "https://github.com/astral-sh/uv"
authors = ["uv"]
license = "MIT OR Apache-2.0"

[workspace.dependencies]
uv-audit = { version = "0.0.59", path = "crates/uv-audit" }
uv-auth = { version = "0.0.59", path = "crates/uv-auth" }
uv-bin-install = { version = "0.0.59", path = "crates/uv-bin-install" }
uv-build-backend = { version = "0.0.59", path = "crates/uv-build-backend" }
uv-build-frontend = { version = "0.0.59", path = "crates/uv-build-frontend" }
uv-cache = { version = "0.0.59", path = "crates/uv-cache" }
uv-cache-info = { version = "0.0.59", path = "crates/uv-cache-info" }
uv-cache-key = { version = "0.0.59", path = "crates/uv-cache-key" }
uv-cli = { version = "0.0.59", path = "crates/uv-cli" }
uv-client = { version = "0.0.59", path = "crates/uv-client" }
uv-configuration = { version = "0.0.59", path = "crates/uv-configuration" }
uv-console = { version = "0.0.59", path = "crates/uv-console" }
uv-dirs = { version = "0.0.59", path = "crates/uv-dirs" }
uv-dispatch = { version = "0.0.59", path = "crates/uv-dispatch" }
uv-distribution = { version = "0.0.59", path = "crates/uv-distribution" }
uv-distribution-filename = { version = "0.0.59", path = "crates/uv-distribution-filename" }
uv-distribution-types = { version = "0.0.59", path = "crates/uv-distribution-types" }
uv-errors = { version = "0.0.59", path = "crates/uv-errors" }
uv-extract = { version = "0.0.59", path = "crates/uv-extract" }
uv-fastid = { version = "0.0.59", path = "crates/uv-fastid" }
uv-flags = { version = "0.0.59", path = "crates/uv-flags" }
uv-fs = { version = "0.0.59", path = "crates/uv-fs", features = [
  "serde",
