uv-globfilter = { version = "0.0.59", path = "crates/uv-globfilter" }
uv-install-wheel = { version = "0.0.59", path = "crates/uv-install-wheel", default-features = false }
uv-installer = { version = "0.0.59", path = "crates/uv-installer" }
uv-keyring = { version = "0.0.59", path = "crates/uv-keyring" }
uv-logging = { version = "0.0.59", path = "crates/uv-logging" }
uv-macros = { version = "0.0.59", path = "crates/uv-macros" }
uv-metadata = { version = "0.0.59", path = "crates/uv-metadata" }
uv-netrc = { version = "0.0.59", path = "crates/uv-netrc" }
