uv-torch = { version = "0.0.59", path = "crates/uv-torch" }
uv-trampoline-builder = { version = "0.0.59", path = "crates/uv-trampoline-builder" }
uv-types = { version = "0.0.59", path = "crates/uv-types" }
uv-unix = { version = "0.0.59", path = "crates/uv-unix" }
uv-version = { version = "0.11.26", path = "crates/uv-version" }
uv-virtualenv = { version = "0.0.59", path = "crates/uv-virtualenv" }
uv-warnings = { version = "0.0.59", path = "crates/uv-warnings" }
uv-windows = { version = "0.0.59", path = "crates/uv-windows" }
uv-workspace = { version = "0.0.59", path = "crates/uv-workspace" }

ambient-id = { version = "0.0.11", default-features = false, features
